const crypto = require('crypto');
const workerId = `n8n-eval-${Date.now()}`;
const results = [];

for (const item of $input.all()) {
  const payload = JSON.stringify({ event: 'evaluation.process', data: { jobId: item.json.id, workerId } });
  const timestamp = Math.floor(Date.now() / 1000).toString();
  const nonce = crypto.randomUUID();
  const signingString = `${timestamp}.${nonce}.${payload}`;
  const signature = crypto.createHmac('sha256', $env.WEBHOOK_SECRET).update(signingString).digest('hex');
  results.push({ json: { payload, timestamp, nonce, signature } });
}
return results;
